import fs from 'node:fs';
import path from 'node:path';
import { base64 } from '../utils';

const contentBase64 = '';
export const file1 = {
  // PDF of "Hello World"
  fileName: 'hello-world.pdf',
  contentBase64,
  buffer: base64.toBuffer(contentBase64),
};

const filePath2 = path.resolve(path.join(__dirname, '/', 'sample.pdf'));
const buffer = fs.readFileSync(filePath2);
export const file2 = {
  fileName: 'sample.pdf',
  filePath: filePath2,
  buffer,
  contentBase64: base64.fromBuffer(buffer),
};
